import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.BGkQCay2.js";const g=JSON.parse('{"title":"GPU & Compute with SIR","description":"","frontmatter":{},"headers":[],"relativePath":"guide/gpu/index.md","filePath":"guide/gpu/index.md"}'),n={name:"guide/gpu/index.md"};function l(r,e,o,d,p,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="gpu-compute-with-sir" tabindex="-1">GPU &amp; Compute with SIR <a class="header-anchor" href="#gpu-compute-with-sir" aria-label="Permalink to &quot;GPU &amp; Compute with SIR&quot;">​</a></h1><p>SIR (Static Intermediate Representation) is Vex&#39;s heterogeneous compute layer. It allows the compiler and runtime to compile, optimize, and dispatch tensor-style operations to parallel execution targets (CPUs and GPUs) transparently.</p><hr><h2 id="the-zero-cost-perception-philosophy" tabindex="-1">The Zero-Cost Perception Philosophy <a class="header-anchor" href="#the-zero-cost-perception-philosophy" aria-label="Permalink to &quot;The Zero-Cost Perception Philosophy&quot;">​</a></h2><p>Vex does not force GPU programming through complex shader languages or custom runtime APIs. Instead, the compiler analyzes standard dataflow inside functions marked with <code>graph fn</code> to automatically construct a SIR Directed Acyclic Graph (DAG) for parallel execution.</p><h3 id="perception-example-dot-product" tabindex="-1">Perception Example: Dot Product <a class="header-anchor" href="#perception-example-dot-product" aria-label="Permalink to &quot;Perception Example: Dot Product&quot;">​</a></h3><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fn</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> dot</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(a</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;, b</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Span</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ta</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> a;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tb</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Tensor</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">f32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> b;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">+</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ta </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tb);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>The compiler detects the element-wise multiplication followed by a sum reduction and lowers it to a SIR <code>Map</code> and <code>Reduce</code> DAG. The runtime then chooses the best execution path based on the input size.</p><hr><h2 id="metal-gpu-backend-architecture" tabindex="-1">Metal GPU Backend Architecture <a class="header-anchor" href="#metal-gpu-backend-architecture" aria-label="Permalink to &quot;Metal GPU Backend Architecture&quot;">​</a></h2><p>The Metal backend integrates SIR code generation with a runtime dispatch system optimized for Apple Silicon.</p><h3 id="_1-msl-compliance-and-type-parity" tabindex="-1">1. MSL Compliance and Type Parity <a class="header-anchor" href="#_1-msl-compliance-and-type-parity" aria-label="Permalink to &quot;1. MSL Compliance and Type Parity&quot;">​</a></h3><ul><li><strong>F64 to F32 Downcasting</strong>: Because many mobile and integrated GPUs do not natively support <code>double</code> precision, the compiler downcasts <code>DType::F64</code> to <code>float</code> in Metal Shading Language (MSL).</li><li><strong>Deferred Constants</strong>: MSL prohibits non-constant variables at global scope. The compiler automatically defers global constants, emitting them locally inside the generated kernels.</li><li><strong>Literal Precision</strong>: All literal float values are formatted with explicit type suffixes (e.g., <code>1.0f</code> or <code>1e-5f</code>) to prevent MSL compiler warnings and type ambiguities.</li></ul><h3 id="_2-parallel-two-pass-reduction" tabindex="-1">2. Parallel Two-Pass Reduction <a class="header-anchor" href="#_2-parallel-two-pass-reduction" aria-label="Permalink to &quot;2. Parallel Two-Pass Reduction&quot;">​</a></h3><p>To maximize GPU core utilization on Apple Silicon during complex fused operations (such as Softmax and Normalization), Vex uses a <strong>Two-Pass Reduction</strong> architecture:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Pass 1: reduce_kernel (1 Threadgroup, 256 Threads)</span></span>
<span class="line"><span>  ┌────────────────────────────────────────────────┐</span></span>
<span class="line"><span>  │ Parallel Tree Reduction using Shared Memory    │</span></span>
<span class="line"><span>  └───────────────────────┬────────────────────────┘</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼ Writes partial results</span></span>
<span class="line"><span>                    _scalars buffer (buffer(4))</span></span>
<span class="line"><span>                          │</span></span>
<span class="line"><span>                          ▼ Reads scalar inputs</span></span>
<span class="line"><span>  Pass 2: map_kernel (N Threads, Full GPU Cores)</span></span>
<span class="line"><span>  ┌────────────────────────────────────────────────┐</span></span>
<span class="line"><span>  │ Element-wise computation using unified memory  │</span></span>
<span class="line"><span>  └────────────────────────────────────────────────┘</span></span></code></pre></div><ul><li><strong>Pass 1: <code>reduce_kernel</code></strong>: Launched with exactly <strong>one threadgroup</strong> (256 threads). Threads perform a binary tree reduction using threadgroup shared memory (<code>threadgroup float shared_data[256]</code>) and write the final scalar result to a temporary <code>_scalars</code> buffer.</li><li><strong>Pass 2: <code>map_kernel</code></strong>: Launched with <strong>N threads</strong> to utilize all available GPU compute cores. Threads read the scalar reduction results from the <code>_scalars</code> buffer and execute the element-wise portion of the fused operator in parallel.</li></ul><h3 id="_3-buffer-binding-conventions" tabindex="-1">3. Buffer Binding Conventions <a class="header-anchor" href="#_3-buffer-binding-conventions" aria-label="Permalink to &quot;3. Buffer Binding Conventions&quot;">​</a></h3><p>Vex structures MSL shader parameters using a rigid buffer binding index convention:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Buffer Index</th><th style="text-align:left;">Parameter</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong><code>buffer(0)</code></strong></td><td style="text-align:left;"><code>output</code></td><td style="text-align:left;">Destination pointer for results.</td></tr><tr><td style="text-align:left;"><strong><code>buffer(1)</code></strong></td><td style="text-align:left;"><code>input_0</code></td><td style="text-align:left;">Primary input tensor buffer.</td></tr><tr><td style="text-align:left;"><strong><code>buffer(2)</code></strong></td><td style="text-align:left;"><code>input_1</code></td><td style="text-align:left;">Secondary input tensor buffer (or padding for unary operations).</td></tr><tr><td style="text-align:left;"><strong><code>buffer(3)</code></strong></td><td style="text-align:left;"><code>N</code></td><td style="text-align:left;">Constant integer representing the total number of elements.</td></tr><tr><td style="text-align:left;"><strong><code>buffer(4)</code></strong></td><td style="text-align:left;"><code>_scalars</code></td><td style="text-align:left;">Temporary buffer passing reduction results between passes.</td></tr></tbody></table><hr><h2 id="runtime-deferred-dispatch" tabindex="-1">Runtime Deferred Dispatch <a class="header-anchor" href="#runtime-deferred-dispatch" aria-label="Permalink to &quot;Runtime Deferred Dispatch&quot;">​</a></h2><p>For functions with dynamic, runtime-sized inputs (e.g., <code>Span&lt;f32&gt;</code>), Vex uses a <strong>Deferred Dispatch</strong> strategy to choose the execution path at runtime:</p><ol><li><strong>Length Extraction</strong>: The runtime extracts the length field from the incoming <code>Span</code> structure.</li><li><strong>Complexity Scoring</strong>: The compiler computes a complexity score for the SIR DAG (e.g., <code>Map</code> operations score low, <code>MatMul</code> and <code>Reduce</code> score high) to determine an <code>adjusted_threshold</code>.</li><li><strong>Safety Clamping</strong>: Any input length larger than <code>1GB</code> is clamped to <code>0</code> to force a safe CPU fallback on corrupted memory.</li><li><strong>Branching</strong>: If the input length exceeds the complexity threshold, execution is routed to the <strong>GPU Path</strong> (Metal). Otherwise, it falls back to the <strong>CPU SIMD Path</strong> (NEON/AVX) to avoid GPU launch overhead.</li></ol><div class="warning custom-block"><p class="custom-block-title">UB Prevention: The <code>noinline</code> Attribute</p><p>LLVM optimizations (like scalar replacement of aggregates) can decompose Span structures into registers, corrupting runtime length extraction. To prevent this, all functions using runtime dispatch are marked <code>noinline</code> in the generated LLVM IR, forcing explicit struct <code>extractvalue</code> calls.</p></div><hr><h2 id="special-handling-optimizations" tabindex="-1">Special Handling &amp; Optimizations <a class="header-anchor" href="#special-handling-optimizations" aria-label="Permalink to &quot;Special Handling &amp; Optimizations&quot;">​</a></h2><ul><li><strong>Sentinel Constants (<code>-1.0</code>)</strong>: For dynamic spans, the compiler emits a <code>-1.0</code> sentinel for <code>.len()</code> operations. The runtime automatically replaces this with the actual runtime length before execution.</li><li><strong>Graph-in-Graph Inlining</strong>: To support composability (e.g., <code>softmax</code> calling <code>reduce_max</code>), the compiler performs periodic SIR-level inlining, merging separate graphs into a single DAG to enable global kernel fusion.</li></ul><hr><h2 id="target-architectures-backend-pipelines" tabindex="-1">Target Architectures &amp; Backend Pipelines <a class="header-anchor" href="#target-architectures-backend-pipelines" aria-label="Permalink to &quot;Target Architectures &amp; Backend Pipelines&quot;">​</a></h2><p>Vex compiles and routes Silicon IR (SIR) graphs dynamically based on the platform and hardware configuration:</p><h3 id="_1-cpu-simd-fallback-avx-512-avx2-neon" tabindex="-1">1. CPU SIMD Fallback (AVX-512 / AVX2 / NEON) <a class="header-anchor" href="#_1-cpu-simd-fallback-avx-512-avx2-neon" aria-label="Permalink to &quot;1. CPU SIMD Fallback (AVX-512 / AVX2 / NEON)&quot;">​</a></h3><p>If the array length is below the execution threshold, or if no compatible GPU is detected, Vex routes execution to the CPU:</p><ul><li><strong>Vectorization</strong>: The compiler lowers SIR operations into LLVM vector instructions (e.g., <code>&lt;8 x float&gt;</code>).</li><li><strong>Loop Optimizations</strong>: Loops are annotated with unrolling and vectorization width hints (<code>llvm.loop.vectorize.width</code> and <code>llvm.loop.unroll.enable</code>) to ensure LLVM generates efficient CPU SIMD instructions (AVX-512, AVX2, or ARM NEON).</li></ul><h3 id="_2-apple-silicon-metal-macos" tabindex="-1">2. Apple Silicon Metal (macOS) <a class="header-anchor" href="#_2-apple-silicon-metal-macos" aria-label="Permalink to &quot;2. Apple Silicon Metal (macOS)&quot;">​</a></h3><p>The primary GPU acceleration pathway on macOS:</p><ul><li><strong>Zero-Copy / UMA</strong>: Apple Silicon utilizes a Unified Memory Architecture (UMA). The CPU and GPU share the same memory space, completely eliminating PCIe transfer overhead.</li><li><strong>Dispatch Threshold</strong>: Set to a low <strong>50,000 elements</strong> due to the absence of buffer copying costs.</li></ul><h3 id="_3-vulkan-spir-v-linux-windows" tabindex="-1">3. Vulkan &amp; SPIR-V (Linux / Windows) <a class="header-anchor" href="#_3-vulkan-spir-v-linux-windows" aria-label="Permalink to &quot;3. Vulkan &amp; SPIR-V (Linux / Windows)&quot;">​</a></h3><p>For Linux and Windows platforms, Vex lowers SIR nodes to Vulkan compute shaders:</p><ul><li><strong>SPIR-V Codegen</strong>: The compiler outputs SPIR-V intermediate binary instructions.</li><li><strong>PCIe Transfer Overhead</strong>: Since discrete GPUs (NVIDIA/AMD) require copying input buffers over the PCIe bus, the routing complexity model increases the dispatch threshold to <strong>1,000,000 elements</strong> to amortize latency.</li></ul><h3 id="_4-webgpu-wgsl-web" tabindex="-1">4. WebGPU &amp; WGSL (Web) <a class="header-anchor" href="#_4-webgpu-wgsl-web" aria-label="Permalink to &quot;4. WebGPU &amp; WGSL (Web)&quot;">​</a></h3><p>For WASM/Web applications, Vex lowers graphs directly to WebGPU Shading Language (WGSL):</p><ul><li><strong>WGSL Generation</strong>: Compiles arithmetic and reduction networks into subgroup-accelerated WGSL shaders.</li><li><strong>Dynamic Loading</strong>: Shaders are loaded and compiled by the browser runtime asynchronously.</li></ul><hr><h2 id="backend-support-summary" tabindex="-1">Backend Support Summary <a class="header-anchor" href="#backend-support-summary" aria-label="Permalink to &quot;Backend Support Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Platform / OS</th><th style="text-align:left;">Primary Target</th><th style="text-align:left;">Shader / IR Pipeline</th><th style="text-align:left;">Memory Model</th><th style="text-align:left;">Status</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>macOS</strong></td><td style="text-align:left;"><code>Metal</code></td><td style="text-align:left;">MSL Compiler</td><td style="text-align:left;">Unified (UMA)</td><td style="text-align:left;">Fully Supported (Optimized)</td></tr><tr><td style="text-align:left;"><strong>Linux</strong></td><td style="text-align:left;"><code>Vulkan</code></td><td style="text-align:left;">SPIR-V Codegen</td><td style="text-align:left;">Discrete / Copied</td><td style="text-align:left;">Supported</td></tr><tr><td style="text-align:left;"><strong>Windows</strong></td><td style="text-align:left;"><code>Vulkan</code></td><td style="text-align:left;">SPIR-V Codegen</td><td style="text-align:left;">Discrete / Copied</td><td style="text-align:left;">Supported</td></tr><tr><td style="text-align:left;"><strong>Web / WASM</strong></td><td style="text-align:left;"><code>WebGPU</code></td><td style="text-align:left;">WGSL Code Generator</td><td style="text-align:left;">Sandboxed / Copied</td><td style="text-align:left;">Supported</td></tr><tr><td style="text-align:left;"><strong>Any (Fallback)</strong></td><td style="text-align:left;"><code>CPU SIMD</code></td><td style="text-align:left;">LLVM Vector IR</td><td style="text-align:left;">CPU Cache</td><td style="text-align:left;">Fully Supported</td></tr></tbody></table><hr><h2 id="runtime-controls" tabindex="-1">Runtime Controls <a class="header-anchor" href="#runtime-controls" aria-label="Permalink to &quot;Runtime Controls&quot;">​</a></h2><p>You can override the automatic GPU dispatch decisions using environment variables:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Disable GPU offloading (force CPU SIMD fallback)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_NO_GPU</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program.vx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Force GPU offloading regardless of cost model</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_FORCE_GPU</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program.vx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Select a specific GPU backend</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_GPU_BACKEND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">metal</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vulkan</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">webgpu</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program.vx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Enable verbose dispatch logging</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">VEX_DISPATCH_VERBOSE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> vex</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> program.vx</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="/docs/guide/simd">SIMD Auto-Vectorization</a> - CPU SIMD details</li><li><a href="/docs/guide/memory/vumm">VUMM Memory Model</a> - Automatic memory management</li><li><a href="/docs/guide/advanced/performance">Performance</a> - Optimization techniques</li></ul>`,52)])])}const u=t(n,[["render",l]]);export{g as __pageData,u as default};
